solutions.cpp:
class Solution {
public:
    long long solve(long long n, long long m, long long p) {
        long long res = 1;
        while (n > 0) {
            if (n % 2 == 1) res = (res * m) % p;
            m = (m * m) % p;
            n >>= 1;
        }
        return res;
    }
};

int main() {
    Solution solution;
    long long n, m, p;
    cin >> n >> m >> p;
    cout << solution.solve(n, m, p) << endl;
    return 0;
}
